module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output reg [WIDTH-1:0]	rdata
);

reg [WIDTH-1:0] ram [DEPTH-1:0];
reg [ADDR_WIDTH-1:0] waddr, raddr;
always @(posedge wclk) begin
    if (wenc)
        ram[waddr] <= wdata;
end
always @(posedge rclk) begin
    rdata <= ram[raddr];
end

reg [ADDR_WIDTH:0] wptr = 0;
reg wenc = 0;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn)
        wptr <= 0;
    else if (winc && !wfull)
        wptr <= wptr + 1;
end
assign wfull = (wptr[ADDR_WIDTH] ^ wptr[ADDR_WIDTH-1]) && (wptr[ADDR_WIDTH-2:0] == wptr[ADDR_WIDTH-3:0]);

reg [ADDR_WIDTH:0] rptr = 0;
reg renc = 0;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn)
        rptr <= 0;
    else if (rinc && !rempty)
        rptr <= rptr + 1;
end
assign rempty = (rptr == wptr);

reg [ADDR_WIDTH:0] rptr_sync1 = 0, rptr_sync2 = 0;
always @(posedge wclk) begin
    rptr_sync1 <= rptr;
    rptr_sync2 <= rptr_sync1;
end

reg [ADDR_WIDTH:0] wptr_sync1 = 0, wptr_sync2 = 0;
always @(posedge rclk) begin
    wptr_sync1 <= wptr;
    wptr_sync2 <= wptr_sync1;
end

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
